import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface HourlyUVForecast {
  hour: string;
  uvIndex: number;
}

interface UVData {
  location: string;
  current: {
    uvIndex: number;
    riskCategory: string;
  };
  hourlyUVForecast: HourlyUVForecast[];
}

export default function Widget() {
  const uvData = response.data as UVData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              {uvData.location}
            </Typography>
            <Typography variant="h3" fontWeight={300} sx={{ my: 0.5 }}>
              UV Index: {uvData.current.uvIndex}
            </Typography>
            <Chip label={uvData.current.riskCategory} color="primary" sx={{ backgroundColor: response.meta.primaryColor, color: '#FFFFFF' }} />
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <BarChart
              height={140}
              series={[
                {
                  data: uvData.hourlyUVForecast.map(f => f.uvIndex),
                  color: response.meta.accentColor,
                },
              ]}
              xAxis={[
                {
                  data: uvData.hourlyUVForecast.map(f => f.hour),
                  scaleType: 'band',
                  tickLabelStyle: {
                    fontSize: 11,
                    fill: '#6B7280',
                  },
                },
              ]}
              yAxis={[
                {
                  tickLabelStyle: {
                    fontSize: 11,
                    fill: '#6B7280',
                  },
                },
              ]}
              margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
              sx={{
                '& .MuiBarElement-root': {
                  rx: 4,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
